={{ (() => {
  const v = $json.body?.data?.new_value;
  const toStr = (x) => {
    if (x == null) return '';
    if (Array.isArray(x)) return x.map(toStr).filter(Boolean).join(',');
    if (typeof x === 'object') {
      if ('value' in x) return toStr(x.value);
      if ('label' in x) return toStr(x.label);
      if ('id' in x) return toStr(x.id);
    }
    let s = String(x);
    try { const parsed = JSON.parse(s); return toStr(parsed); } catch(_) {}
    return s;
  };
  const raw = toStr(v).trim().toLowerCase();
  return raw.normalize ? raw.normalize('NFD').replace(/[\u0300-\u036f]/g,'') : raw;
})()}}

={{ (() => {
  const norm = (v) => {
    const out = [];
    const push = s => { s = String(s ?? '').trim(); if (s) out.push(s); };
    if (Array.isArray(v)) for (const x of v) (x && typeof x==='object' && x.id!=null) ? push(x.id) : push(x);
    else if (v && typeof v==='object' && v.id!=null) push(v.id);
    else if (typeof v==='string') v.split(',').forEach(push);
    return Array.from(new Set(out));
  };

  const curr = norm($json.rede);
  const prev = norm($json.prevRedeId);

  // Se não há valor anterior, tudo que existe hoje é considerado "novo"
  if (!prev.length) {
    return curr;
  }

  const sPrev = new Set(prev);
  return curr.filter(id => !sPrev.has(id));
})() }}

={{ (() => {
  const norm = (v) => {
    const out = [];

    const pushRaw = (s) => {
      s = String(s ?? '').trim();
      if (!s) return;
      if (s === '[]') return;                         // ignora literal "[]"
      out.push(s);
    };

    const push = (val) => {
      if (val == null) return;

      if (Array.isArray(val)) {
        val.forEach(push);
        return;
      }

      if (typeof val === 'object') {
        if (val.id != null) { pushRaw(val.id); return; }
        if ('value' in val) { push(val.value); return; }
        return; // ignora objetos sem id/value
      }

      if (typeof val === 'string') {
        const s = val.trim();
        // tenta JSON: "[...]", "{\"id\":\"123\"}", "\"abc\""
        try {
          const parsed = JSON.parse(s);
          push(parsed);
          return;
        } catch (_) {}

        // como fallback, divide por vírgula
        s.split(',').forEach(tok => pushRaw(tok));
        return;
      }

      // number/boolean etc.
      pushRaw(val);
    };

    push(v);
    // dedup + filtra o literal "[]"
    return Array.from(new Set(out.filter(s => s && s !== '[]')));
  };

  const curr = norm($json.rede);
  const prev = norm($json.prevRedeId);

  const sCurr = new Set(curr);
  return prev.filter(id => !sCurr.has(id));
})() }}

